INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (2060, 210297, 5, 2283, '较量', '你不喜欢这个词――较量，可是每次我们不都是在较量吗？除了弄到彼此间都伤痕累累的，才会想起对方的好，不是吗？这次的较量还想维持多久呢？1个月，1年，2年，还有4年，或者是更长呢？不用你说，我就晓得了，明白了，了解了，这次的较量是无限期的，无止境的。你要离开了，换上一副新的心情，新的脸孔，去面对你周遭的人们。你不想听我的解释，我也不想丢失自己的尊严，我们就这样继续耗下去吗？等到彼此之间都失去了回头的勇气，和拥抱的感动吗？过去美丽的回忆，正慢慢的在你记忆里磨灭，在你心中渐渐的沉淀，在你生命中悄悄的消失。最终，我们会行同陌生人般的擦肩而过，或许我们以后根本没有见面的可能了。一段曾经惊天动地的感情，就这么残酷的结束了。随着出国日子的临近，我重复拨着你的号码，再重复的按掉，总希望你会低头，你会放弃这场较量，你会给我一个新的希望去等待。可是这一切看上去，都是可笑的思量，太了解你了，没有任何人可以与你较量，也没有任何人可以让你留恋。最终，我们之间的较量在延续，等到下辈子，你我都不要改名字，我还想和你继续较量。与你较量的时候可以完全拥有你，可以让全世界都知道你是我的，只属于我的，无人可以取代你的地位，一个我永远都想较量的对手。我等你。。。。。', '你不喜欢这个词――较量，可是每次我们不都是在较量吗？除了弄到彼此间都伤痕累累的，才会想起对方的好，不是吗？这次的较量还想维持多久呢？1个月，1年，2年，还有4年，或者是更长呢？不用你说，我就晓得了，明白了，了解了，这次的较量是无限期的，无止境的。你要离开了，换上一副新的心情，新的脸孔，去面对你周遭的人们。你不想听我的解释，我也不想丢失自己的尊严，我们就这样继续耗下去吗？等到彼此之间都失去了回头的勇气，和拥抱的感动吗？过去美丽的回忆，正慢慢的在你记忆里磨灭，在你心中渐渐的沉淀，在你生命中悄悄的消失。最终，我们会行同陌生人般的擦肩而过，或许我们以后根本没有见面的可能了。一段曾经惊天动地的感情，就这么残酷的结束了。随着出国日子的临近，我重复拨着你的号码，再重复的按掉，总希望你会低头，你会放弃这场较量，你会给我一个新的希望去等待。可是这一切看上去，都是可笑的思量，太了解你了，没有任何人可以与你较量，也没有任何人可以让你留恋。最终，我们之间的较量在延续，等到下辈子，你我都不要改名字，我还想和你继续较量。与你较量的时候可以完全拥有你，可以让全世界都知道你是我的，只属于我的，无人可以取代你的地位，一个我永远都想较量的对手。我等你。。。。。', '在爱与被爱之间，我选择放弃；在放弃和争取之间，我选择去爱。', '2003-08-01 13:35:00', 9, '20030819191505_bbsid_210297_board_5_78eed723b6.html', '20030819191505');
